1	//! The individual wellformedness checks. Each produces zero or one `WfError`
2	//! (one topic block). Message bodies reproduce oracle byte formatting.
3	
4	use crate::ast::*;
5	use crate::pretty::{pp_fact, pp_rule, pp_term, pp_var};
6	use crate::report::WfError;
