8	// ---- Topic strings (exact, including significant whitespace) ----
9	pub const T_UNBOUND: &str = "Unbound variables";
10	pub const T_FRESH_PUB: &str = "Fresh public constants";
11	pub const T_PUBNAMES: &str = "Public constants with mismatching capitalization";
12	pub const T_SORTS: &str = "Variable with mismatching sorts or capitalization";
13	pub const T_RESERVED: &str = "Reserved names";
14	pub const T_RESERVED_PREFIX: &str = "Reserved prefixes";
15	pub const T_FR: &str = "Fr facts must only use a fresh- or a msg-variable";
16	pub const T_SPECIAL: &str = "Special facts";
17	pub const T_FACT_CAP: &str = "Fact capitalization issues";
18	pub const T_ARITY: &str = "Fact arity issues";
19	pub const T_MULT: &str = "Fact multiplicity issues";
20	pub const T_LHSRHS: &str = "Facts occur in the left-hand-side but not in any right-hand-side ";
21	pub const T_LEFT: &str = "Left rule";
22	pub const T_RIGHT: &str = "Right rule";
23	pub const T_QUANT_SORTS: &str = "Quantifier sorts";
24	pub const T_FORMULA_TERMS: &str = "Formula terms";
25	pub const T_GUARD: &str = " Formula guardedness";
26	pub const T_LEMMA_ANNOT: &str = "Lemma annotations";
27	pub const T_MULRESTRICT: &str = "Multiplication restriction of rules";
28	pub const T_NAT: &str = "Nat Sorts";
29	pub const T_SUBTERM: &str = "Subterm Convergence Warning";
