82	// ---------------------------------------------------------------------------
83	// AST traversal helpers
84	// ---------------------------------------------------------------------------
85	
86	/// The protocol rules of a theory (excludes intruder rules).
87	pub fn protocol_rules(thy: &Theory) -> Vec<&Rule> {
88	    thy.items
89	        .iter()
90	        .filter_map(|it| match it {
91	            TheoryItem::Rule(r) => Some(r),
92	            _ => None,
93	        })
94	        .collect()
95	}
96	
97	fn collect_term_vars(t: &Term, out: &mut Vec<VarSpec>) {
98	    match t {
99	        Term::Var(v) => out.push(v.clone()),
100	        Term::App(_, args) | Term::Pair(args) => {
101	            for a in args {
102	                collect_term_vars(a, out);
103	            }
104	        }
105	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
106	            collect_term_vars(a, out);
107	            collect_term_vars(b, out);
108	        }
109	        Term::PatMatch(inner) => collect_term_vars(inner, out),
110	        _ => {}
111	    }
112	}
113	
114	fn collect_fact_vars(f: &Fact, out: &mut Vec<VarSpec>) {
115	    for a in &f.args {
116	        collect_term_vars(a, out);
117	    }
118	}
119	
120	fn collect_facts_vars(fs: &[Fact], out: &mut Vec<VarSpec>) {
121	    for f in fs {
122	        collect_fact_vars(f, out);
123	    }
124	}
125	
126	/// Collect public-constant literals (name only) from a term.
127	fn collect_pub_lits(t: &Term, out: &mut Vec<String>) {
128	    match t {
129	        Term::PubLit(s) => out.push(s.clone()),
130	        Term::App(_, args) | Term::Pair(args) => {
131	            for a in args {
132	                collect_pub_lits(a, out);
133	            }
134	        }
135	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
136	            collect_pub_lits(a, out);
137	            collect_pub_lits(b, out);
138	        }
139	        Term::PatMatch(inner) => collect_pub_lits(inner, out),
140	        _ => {}
141	    }
142	}
143	
144	/// Collect fresh-name literals (`~'foo'`) from a term, rendered as the oracle
145	/// prints them.
146	fn collect_fresh_lits(t: &Term, out: &mut Vec<String>) {
147	    match t {
148	        Term::FreshLit(_) => out.push(pp_term(t)),
149	        Term::App(_, args) | Term::Pair(args) => {
150	            for a in args {
151	                collect_fresh_lits(a, out);
152	            }
153	        }
154	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
155	            collect_fresh_lits(a, out);
156	            collect_fresh_lits(b, out);
157	        }
158	        Term::PatMatch(inner) => collect_fresh_lits(inner, out),
159	        _ => {}
160	    }
161	}
162	
163	/// Collect maximal multiplication (`*`) subterms of a term, rendered as the
164	/// oracle prints them. A product is maximal: its own operands are not
165	/// descended into.
166	fn collect_mult_terms(t: &Term, out: &mut Vec<String>) {
167	    if let Term::BinOp(BinOp::Mult, _, _) = t {
168	        out.push(pp_term(t));
169	        return;
170	    }
171	    match t {
172	        Term::App(_, args) | Term::Pair(args) => {
173	            for a in args {
174	                collect_mult_terms(a, out);
175	            }
176	        }
177	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
178	            collect_mult_terms(a, out);
179	            collect_mult_terms(b, out);
180	        }
181	        Term::PatMatch(inner) => collect_mult_terms(inner, out),
182	        _ => {}
183	    }
184	}
