186	/// Indent every line of a (possibly multi-line) block by `n` spaces.
187	fn indent_block(s: &str, n: usize) -> String {
188	    let pad = " ".repeat(n);
189	    s.lines()
190	        .map(|l| format!("{}{}", pad, l))
191	        .collect::<Vec<_>>()
192	        .join("\n")
193	}
194	
195	/// Word-fill (Wadler/Leijen `fillSep`) at the given `width` with a leading
196	/// `indent` of spaces on every line. A word is pushed onto the current line
197	/// while it fits (column + 1 + word <= width), otherwise a new line begins.
198	fn fill_words(words: &[String], indent: usize, width: usize) -> String {
199	    let pad = " ".repeat(indent);
200	    let mut lines: Vec<String> = Vec::new();
201	    let mut cur = String::new();
202	    let mut col = 0usize;
203	    for w in words {
204	        let wlen = w.chars().count();
205	        if cur.is_empty() {
206	            cur = format!("{}{}", pad, w);
207	            col = indent + wlen;
208	        } else if col + 1 + wlen <= width {
209	            cur.push(' ');
210	            cur.push_str(w);
211	            col += 1 + wlen;
212	        } else {
213	            lines.push(std::mem::take(&mut cur));
214	            cur = format!("{}{}", pad, w);
215	            col = indent + wlen;
216	        }
217	    }
218	    if !cur.is_empty() {
219	        lines.push(cur);
220	    }
221	    lines.join("\n")
222	}
223	
224	fn var_needs_binding(v: &VarSpec) -> bool {
225	    matches!(
226	        v.sort,
227	        SortHint::Fresh | SortHint::Msg | SortHint::Untagged | SortHint::Nat
228	    )
229	}
230	
231	fn var_key(v: &VarSpec) -> (String, u64, i32) {
232	    (v.name.clone(), v.idx, sort_rank(v.sort))
233	}
234	
235	fn sort_rank(s: SortHint) -> i32 {
236	    match s {
237	        SortHint::Msg => 0,
238	        SortHint::Pub => 1,
239	        SortHint::Fresh => 2,
240	        SortHint::Node => 3,
241	        SortHint::Nat => 4,
242	        SortHint::Untagged => 5,
243	        SortHint::Suffix(_) => 6,
244	    }
245	}
246	
247	fn dedup_vars(mut vs: Vec<VarSpec>) -> Vec<VarSpec> {
248	    vs.sort_by_key(var_key);
249	    vs.dedup_by_key(|v| var_key(v));
250	    vs
251	}
252	
253	// ---------------------------------------------------------------------------
254	// 1. Unbound variables
255	// ---------------------------------------------------------------------------
256	pub fn unbound_variables(thy: &Theory) -> Vec<WfError> {
257	    let mut entries: Vec<String> = Vec::new();
258	    for r in protocol_rules(thy) {
259	        // Bound = variables in premises plus let-bound variables.
260	        let mut bound: Vec<VarSpec> = Vec::new();
261	        collect_facts_vars(&r.premises, &mut bound);
262	        for lb in &r.let_block {
263	            collect_term_vars(&lb.var, &mut bound);
264	        }
265	        let bound: std::collections::HashSet<(String, u64, i32)> =
266	            bound.iter().map(var_key).collect();
267	
268	        // Used = variables in actions, conclusions, embedded restrictions,
269	        // and the right-hand-sides of let bindings.
270	        let mut used: Vec<VarSpec> = Vec::new();
271	        collect_facts_vars(&r.actions, &mut used);
272	        collect_facts_vars(&r.conclusions, &mut used);
273	        for lb in &r.let_block {
274	            collect_term_vars(&lb.value, &mut used);
275	        }
276	
277	        let mut unbound: Vec<VarSpec> = used
278	            .into_iter()
279	            .filter(var_needs_binding)
280	            .filter(|v| !bound.contains(&var_key(v)))
281	            .collect();
282	        unbound = dedup_vars(unbound);
283	        // Report order: by base name then index.
284	        unbound.sort_by(|a, b| a.name.cmp(&b.name).then(a.idx.cmp(&b.idx)));
285	
286	        if !unbound.is_empty() {
287	            let names: Vec<String> = unbound.iter().map(pp_var).collect();
288	            entries.push(format!(
289	                "  rule `{}' has unbound variables: \n    {}",
290	                r.name,
291	                names.join(", ")
292	            ));
293	        }
294	    }
295	    if entries.is_empty() {
296	        vec![]
297	    } else {
298	        vec![WfError::new(T_UNBOUND, entries.join("\n  \n"))]
299	    }
300	}
301	
302	// ---------------------------------------------------------------------------
303	// 3. Variable with mismatching sorts or capitalization
304	// ---------------------------------------------------------------------------
305	pub fn mismatching_sorts(thy: &Theory) -> Vec<WfError> {
306	    let mut rule_entries: Vec<String> = Vec::new();
307	    for r in protocol_rules(thy) {
308	        let mut vars: Vec<VarSpec> = Vec::new();
309	        collect_facts_vars(&r.premises, &mut vars);
310	        collect_facts_vars(&r.actions, &mut vars);
311	        collect_facts_vars(&r.conclusions, &mut vars);
312	
313	        // Group by (lowercased base name, index): `$x.1` and `x.2` are
314	        // different variables and never clash (probes s5_idx / s5_capdiff).
315	        // A group with >1 distinct variant (sort class + exact name) is a
316	        // conflict; suffix-sort and sigil spellings of the same sort are the
317	        // SAME variant (s5_suffix).
318	        type Variant = (i32, String); // (sort-class rank, exact name)
319	        let mut groups: Vec<((String, u64), Vec<Variant>)> = Vec::new();
320	        for v in &vars {
321	            let key = (v.name.to_lowercase(), v.idx);
322	            let variant = (class_rank(var_class(v)), v.name.clone());
323	            match groups.iter_mut().find(|(k, _)| *k == key) {
324	                Some((_, variants)) => {
325	                    if !variants.contains(&variant) {
326	                        variants.push(variant);
327	                    }
328	                }
329	                None => groups.push((key, vec![variant])),
330	            }
331	        }
332	        let mut conflicts: Vec<((String, u64), Vec<Variant>)> = groups
333	            .into_iter()
334	            .filter(|(_, vs)| vs.len() > 1)
335	            .map(|(k, mut vs)| {
336	                // Variants ordered by sort class ($ < ~ < msg < %), then by
337	                // exact name (probes s5_all4 / s5_crossname / s5_capord).
338	                vs.sort();
339	                (k, vs)
340	            })
341	            .collect();
342	        if conflicts.is_empty() {
343	            continue;
344	        }
345	        // Groups ordered by their (lowercased name, index) key (s5_groups).
346	        conflicts.sort_by(|a, b| a.0.cmp(&b.0));
347	        let mut body = format!("  rule `{}': ", r.name);
348	        for (i, ((_, idx), variants)) in conflicts.iter().enumerate() {
349	            if i > 0 {
350	                body.push_str("\n    ");
351	            }
352	            let rendered: Vec<String> = variants
353	                .iter()
354	                .map(|(rank, name)| variant_string(*rank, name, *idx))
355	                .collect();
356	            body.push_str(&format!("\n    {}. {}", i + 1, rendered.join(", ")));
357	        }
358	        rule_entries.push(body);
359	    }
360	    if rule_entries.is_empty() {
361	        return vec![];
362	    }
363	    let header = "Possible reasons:\n1. Identifiers are case sensitive, i.e.,'x' and 'X' are considered to be different.\n2. The same holds for sorts:, i.e., '$x', 'x', and '~x' are considered to be different.\n";
364	    let msg = format!("{}\n{}", header, rule_entries.join("\n  \n"));
365	    vec![WfError::new(T_SORTS, msg)]
366	}
367	
368	/// Report-order rank of a sort class in the variant listing: `$x, ~x, x, %x`
369	/// (probe s5_all4; Node placement unobserved - listed last).
370	fn class_rank(c: SortClass) -> i32 {
371	    match c {
372	        SortClass::Pub => 0,
373	        SortClass::Fresh => 1,
374	        SortClass::Msg => 2,
375	        SortClass::Nat => 3,
376	        SortClass::Node => 4,
377	    }
378	}
379	
380	/// A variant rendered with its sort sigil and the group's index suffix
381	/// (suffix-sorted spellings render with the sigil too - probe s5_suffix2).
382	fn variant_string(rank: i32, name: &str, idx: u64) -> String {
383	    let sigil = match rank {
384	        0 => "$",
385	        1 => "~",
386	        3 => "%",
387	        4 => "#",
388	        _ => "",
389	    };
390	    if idx > 0 {
391	        format!("{}{}.{}", sigil, name, idx)
392	    } else {
393	        format!("{}{}", sigil, name)
394	    }
395	}
396	
397	// ---------------------------------------------------------------------------
398	// 4. Reserved names
399	// ---------------------------------------------------------------------------
400	pub fn reserved_names(thy: &Theory) -> Vec<WfError> {
401	    let mut entries: Vec<String> = Vec::new();
402	    for r in protocol_rules(thy) {
403	        // On the left/right the reserved set is {K,KU,KD}; in the middle
404	        // (actions) the I/O facts In/Out/Fr are reserved too (observed z9/z11).
405	        // Matching is via the builtin normalization (`Ku` hits as `!KU( x )` -
406	        // probe t5_ku_all).
407	        for (facts, phrase, middle) in [
408	            (&r.premises, "left-hand-side", false),
409	            (&r.actions, "the middle", true),
410	            (&r.conclusions, "the right-hand-side", false),
411	        ] {
412	            let hits: Vec<Fact> = facts
413	                .iter()
414	                .map(canon_fact)
415	                .filter(|f| is_reserved(&f.name) || (middle && is_special(&f.name)))
416	                .collect();
417	            if hits.is_empty() {
418	                continue;
419	            }
420	            let rendered: Vec<String> = hits.iter().map(pp_fact).collect();
421	            entries.push(format!(
422	                "  Rule `{}' contains facts with reserved names on {}:\n    {}",
423	                r.name,
424	                phrase,
425	                rendered.join(", ")
426	            ));
427	        }
428	    }
429	    if entries.is_empty() {
430	        vec![]
431	    } else {
432	        vec![WfError::new(T_RESERVED, entries.join("\n  \n"))]
433	    }
434	}
435	
436	// ---------------------------------------------------------------------------
437	// 5. Fr facts must only use a fresh- or a msg-variable
438	// ---------------------------------------------------------------------------
439	pub fn fr_facts(thy: &Theory) -> Vec<WfError> {
440	    let mut entries: Vec<String> = Vec::new();
441	    for r in protocol_rules(thy) {
442	        for facts in [&r.premises, &r.conclusions] {
443	            for f in facts {
444	                let f = canon_fact(f);
445	                if f.name != "Fr" {
446	                    continue;
447	                }
448	                let ok = f.args.len() == 1
449	                    && matches!(
450	                        &f.args[0],
451	                        Term::Var(v) if matches!(v.sort, SortHint::Fresh | SortHint::Msg | SortHint::Untagged)
452	                    );
453	                if !ok {
454	                    entries.push(format!("  rule `{}' fact: {}", r.name, pp_fact(&f)));
455	                }
456	            }
457	        }
458	    }
459	    if entries.is_empty() {
460	        vec![]
461	    } else {
462	        vec![WfError::new(T_FR, entries.join("\n  \n"))]
463	    }
464	}
465	
466	// ---------------------------------------------------------------------------
467	// 6. Special facts (disallowed I/O facts in wrong position)
468	// ---------------------------------------------------------------------------
469	pub fn special_facts(thy: &Theory) -> Vec<WfError> {
470	    let mut entries: Vec<String> = Vec::new();
471	    for r in protocol_rules(thy) {
472	        // Premise side: `Out` is disallowed (builtin-normalized; `FR(x)` in a
473	        // conclusion reports as `Fr( x )` - probe t5_up_inout).
474	        let lhs: Vec<String> = r
475	            .premises
476	            .iter()
477	            .map(canon_fact)
478	            .filter(|f| f.name == "Out")
479	            .map(|f| pp_fact(&f))
480	            .collect();
481	        if !lhs.is_empty() {
482	            entries.push(format!(
483	                "  rule `{}' uses disallowed facts on left-hand-side:\n    {}",
484	                r.name,
485	                lhs.join(", ")
486	            ));
487	        }
488	        // Conclusion side: `In` and `Fr` are disallowed.
489	        let rhs: Vec<String> = r
490	            .conclusions
491	            .iter()
492	            .map(canon_fact)
493	            .filter(|f| f.name == "In" || f.name == "Fr")
494	            .map(|f| pp_fact(&f))
495	            .collect();
496	        if !rhs.is_empty() {
497	            entries.push(format!(
498	                "  rule `{}' uses disallowed facts on right-hand-side:\n    {}",
499	                r.name,
500	                rhs.join(", ")
501	            ));
502	        }
503	    }
504	    if entries.is_empty() {
505	        vec![]
506	    } else {
507	        vec![WfError::new(T_SPECIAL, entries.join("\n  \n"))]
508	    }
509	}
