515	struct FactUse {
516	    label: &'static str, // "Rule" or "Lemma"
517	    owner: String,       // rule/lemma name
518	    arity: usize,
519	    persistent: bool,
520	    render: String, // pp_fact for rules; raw Haskell `Fact {..}` show for lemmas
521	}
