523	/// Raw Haskell `Show` of a lemma-sourced fact, as the oracle prints it in the
524	/// arity/multiplicity blocks (observed r3_lemarity / r3_lemmult):
525	///   Fact {factTag = ProtoFact Linear "Act" 2, factAnnotations = fromList [],
526	///         factTerms = [Bound 2,Bound 1]}
527	/// `factTerms` uses the same de Bruijn / Free rendering as the Formula-terms
528	/// check (the binder `stack` is the quantifier context at the atom).
529	fn show_haskell_fact(f: &Fact, stack: &[Binder]) -> String {
530	    let mult = if f.persistent { "Persistent" } else { "Linear" };
531	    let terms: Vec<String> = f.args.iter().map(|a| show_wf_term(a, stack)).collect();
532	    format!(
533	        "Fact {{factTag = ProtoFact {} \"{}\" {}, factAnnotations = fromList [], factTerms = [{}]}}",
534	        mult,
535	        f.name,
536	        f.args.len(),
537	        terms.join(",")
538	    )
539	}
