585	/// Gather every fact occurrence in the theory (name -> uses) in source order.
586	/// Protocol rules contribute their premise/action/conclusion facts (rendered by
587	/// the term pretty-printer); lemmas contribute their formula action facts
588	/// (rendered as the raw Haskell `Fact {..}` show). Restrictions do NOT
589	/// contribute (observed r3_restrarity: a restriction action arity mismatch is
590	/// silent).
591	fn gather_fact_uses(thy: &Theory) -> Vec<(String, Vec<FactUse>)> {
592	    let mut map: Vec<(String, Vec<FactUse>)> = Vec::new();
593	    let push = |name: String, u: FactUse, map: &mut Vec<(String, Vec<FactUse>)>| {
594	        match map.iter_mut().find(|(n, _)| *n == name) {
595	            Some((_, uses)) => uses.push(u),
596	            None => map.push((name, vec![u])),
597	        }
598	    };
599	    for it in &thy.items {
600	        match it {
601	            TheoryItem::Rule(r) => {
602	                for facts in [&r.premises, &r.actions, &r.conclusions] {
603	                    for f in facts {
604	                        push(
605	                            f.name.clone(),
606	                            FactUse {
607	                                label: "Rule",
608	                                owner: r.name.clone(),
609	                                arity: f.args.len(),
610	                                persistent: f.persistent,
611	                                render: pp_fact(f),
612	                            },
613	                            &mut map,
614	                        );
615	                    }
616	                }
617	            }
618	            TheoryItem::Lemma(l) => {
619	                let mut stack: Vec<Binder> = Vec::new();
620	                let mut uses: Vec<(String, FactUse)> = Vec::new();
621	                gather_formula_facts(&l.formula, &mut stack, &l.name, &mut uses);
622	                for (name, u) in uses {
623	                    push(name, u, &mut map);
624	                }
625	            }
626	            _ => {}
627	        }
628	    }
629	    map
630	}
