647	// ---------------------------------------------------------------------------
648	// Fact capitalization issues (precedes Fact arity issues)
649	// ---------------------------------------------------------------------------
650	// Fact names that are equal under ASCII-lowercasing but differ in their exact
651	// spelling (e.g. `Send` vs `SEND`) are distinct facts. Reported like the arity
652	// block, but EVERY occurrence is listed (no per-(rule,cap) deduplication -
653	// observed r3_capord: `Send` twice in one rule yields two items).
654	pub fn fact_capitalization(thy: &Theory) -> Vec<WfError> {
655	    struct Occ {
656	        name: String,
657	        rule: String,
658	        pp: String,
659	    }
660	    let mut occ: Vec<Occ> = Vec::new();
661	    for r in protocol_rules(thy) {
662	        for facts in [&r.premises, &r.actions, &r.conclusions] {
663	            for f in facts {
664	                // Builtin facts normalize their spelling (`Ku` = `KU`), so
665	                // they never produce a capitalization conflict (issue515:
666	                // Ku/KU/Kd/KD yield no such topic).
667	                if canon_builtin(&f.name).is_some() {
668	                    continue;
669	                }
670	                occ.push(Occ {
671	                    name: f.name.clone(),
672	                    rule: r.name.clone(),
673	                    pp: pp_fact(f),
674	                });
675	            }
676	        }
677	    }
678	    // Group by lowercased name, preserving first-seen order.
679	    let mut groups: Vec<(String, Vec<&Occ>)> = Vec::new();
680	    for o in &occ {
681	        let key = o.name.to_lowercase();
682	        match groups.iter_mut().find(|(k, _)| *k == key) {
683	            Some((_, v)) => v.push(o),
684	            None => groups.push((key, vec![o])),
685	        }
686	    }
687	    let mut conflicts: Vec<(String, Vec<String>)> = Vec::new();
688	    for (key, os) in &groups {
689	        let distinct: std::collections::BTreeSet<&String> = os.iter().map(|o| &o.name).collect();
690	        if distinct.len() < 2 {
691	            continue; // no capitalization conflict
692	        }
693	        let items: Vec<String> = os
694	            .iter()
695	            .enumerate()
696	            .map(|(i, o)| {
697	                format!(
698	                    "    {}. Rule `{}', capitalization \"{}\"\n         {}",
699	                    i + 1,
700	                    o.rule,
701	                    o.name,
702	                    o.pp
703	                )
704	            })
705	            .collect();
706	        conflicts.push((key.clone(), items));
707	    }
708	    if conflicts.is_empty() {
709	        return vec![];
710	    }
711	    conflicts.sort_by(|a, b| a.0.cmp(&b.0));
712	    let msg = render_fact_blocks(
713	        &conflicts,
714	        "Fact names are case-sensitive, different capitalizations are considered as different facts, i.e., Fact() is different from FAct(). ",
715	        "Check the capitalization of your fact names.",
716	    );
717	    vec![WfError::new(T_FACT_CAP, msg)]
718	}
