760	    let uses = gather_fact_uses(thy);
761	    let mut conflicts: Vec<(String, Vec<String>)> = Vec::new();
762	    for (name, us) in &uses {
763	        let mults: std::collections::BTreeSet<bool> = us.iter().map(|u| u.persistent).collect();
764	        if mults.len() < 2 {
765	            continue;
766	        }
