923	pub fn public_names_report(thy: &Theory) -> Vec<WfError> {
924	    let mut pairs: Vec<(String, String)> = Vec::new(); // (constName, ruleName)
925	    for r in protocol_rules(thy) {
926	        let mut names: Vec<String> = Vec::new();
927	        for facts in [&r.premises, &r.actions, &r.conclusions] {
928	            for f in facts {
929	                for a in &f.args {
930	                    collect_pub_lits(a, &mut names);
931	                }
932	            }
933	        }
934	        for n in names {
935	            let pair = (n, r.name.clone());
936	            if !pairs.contains(&pair) {
937	                pairs.push(pair);
938	            }
939	        }
940	    }
941	    public_names_report_from_pairs(pairs)
942	}
943	
944	pub fn public_names_report_from_pairs(pairs: Vec<(String, String)>) -> Vec<WfError> {
945	    // Each DISTINCT spelling is attributed to the rule of its FIRST
946	    // occurrence (issue527 target: 'second' is listed only for rule One even
947	    // though later rules use it too).
948	    let mut first_rule: Vec<(String, String)> = Vec::new(); // (name, first rule)
949	    for (name, rule) in &pairs {
950	        if !first_rule.iter().any(|(n, _)| n == name) {
951	            first_rule.push((name.clone(), rule.clone()));
952	        }
953	    }
954	    // Group the distinct spellings by lowercased name; conflicting groups are
955	    // reported sorted by that key (issue527: 'first' group before 'second').
956	    let mut groups: Vec<(String, Vec<(String, String)>)> = Vec::new();
957	    for (name, rule) in &first_rule {
958	        let key = name.to_lowercase();
959	        match groups.iter_mut().find(|(k, _)| *k == key) {
960	            Some((_, v)) => v.push((name.clone(), rule.clone())),
961	            None => groups.push((key, vec![(name.clone(), rule.clone())])),
962	        }
963	    }
964	    groups.retain(|(_, v)| v.len() > 1);
965	    groups.sort_by(|a, b| a.0.cmp(&b.0));
966	    let mut items: Vec<String> = Vec::new();
967	    for (_, mut names) in groups {
968	        // Spellings sorted; consecutive spellings sharing their first rule
969	        // merge into one `rule "R":  name 'a', 'b'` segment.
970	        names.sort();
971	        let mut segs: Vec<(String, Vec<String>)> = Vec::new();
972	        for (name, rule) in names {
973	            match segs.last_mut() {
974	                Some((r, ns)) if *r == rule => ns.push(name),
975	                _ => segs.push((rule, vec![name])),
976	            }
977	        }
978	        let locs: Vec<String> = segs
979	            .into_iter()
980	            .map(|(rule, ns)| {
981	                let quoted: Vec<String> = ns.iter().map(|n| format!("'{}'", n)).collect();
982	                format!("rule \"{}\":  name {}", rule, quoted.join(", "))
983	            })
984	            .collect();
985	        let n = items.len() + 1;
986	        items.push(format!("  {}. {}", n, locs.join(", ")));
987	    }
988	    if items.is_empty() {
989	        return vec![];
990	    }
991	    let header = "Identifiers are case-sensitive, mismatched capitalizations are considered as different, i.e., 'ID' is different from 'id'. Check the capitalization of your identifiers.";
992	    let msg = format!("{}\n\n{}", header, items.join("\n  \n"));
993	    vec![WfError::new(T_PUBNAMES, msg)]
994	}
