1209	/// The argument terms of an atom, in the oracle's reporting order. For an
1210	/// action atom the TEMPORAL variable is reported before the fact arguments
1211	/// (observed via probe r3_actord).
1212	fn atom_terms(a: &Atom) -> Vec<&Term> {
1213	    match a {
1214	        Atom::Eq(x, y) | Atom::Less(x, y) | Atom::LessMset(x, y) | Atom::Subterm(x, y) => {
1215	            vec![x, y]
1216	        }
1217	        Atom::Action(f, t) => {
1218	            let mut v = vec![t];
1219	            v.extend(f.args.iter());
1220	            v
1221	        }
1222	        Atom::Last(t) => vec![t],
1223	        Atom::Pred(f) => f.args.iter().collect(),
1224	    }
1225	}
1226	
1227	/// Walk a formula in source order collecting the RENDERED strings of every
1228	/// ill-formed atom term. Not deduplicated (probe r3_shapes: `x = y & x = y`
1229	/// reports `Free y` twice). Every quantified variable pushes a `(name, class)`
1230	/// binder, so uses are matched sort-aware.
1231	fn collect_ill_terms(
1232	    f: &Formula,
1233	    stack: &mut Vec<Binder>,
1234	    reducible: &std::collections::BTreeSet<String>,
1235	    out: &mut Vec<String>,
1236	) {
1237	    match f {
1238	        Formula::False | Formula::True => {}
1239	        Formula::Atom(a) => {
1240	            for t in atom_terms(a) {
1241	                if term_is_ill_formed(t, stack, reducible) {
1242	                    out.push(show_wf_term(t, stack));
1243	                }
1244	            }
1245	        }
1246	        Formula::Not(g) => collect_ill_terms(g, stack, reducible, out),
1247	        Formula::And(a, b)
1248	        | Formula::Or(a, b)
1249	        | Formula::Implies(a, b)
1250	        | Formula::Iff(a, b) => {
1251	            collect_ill_terms(a, stack, reducible, out);
1252	            collect_ill_terms(b, stack, reducible, out);
1253	        }
1254	        Formula::Forall(vs, g) | Formula::Exists(vs, g) => {
1255	            let n = vs.len();
1256	            for v in vs {
1257	                stack.push((v.name.clone(), v.idx, var_class(v)));
1258	            }
1259	            collect_ill_terms(g, stack, reducible, out);
1260	            for _ in 0..n {
1261	                stack.pop();
1262	            }
1263	        }
1264	    }
1265	}
1266	
1267	fn ill_terms(f: &Formula, reducible: &std::collections::BTreeSet<String>) -> Vec<String> {
1268	    let mut stack: Vec<Binder> = Vec::new();
1269	    let mut terms: Vec<String> = Vec::new();
1270	    collect_ill_terms(f, &mut stack, reducible, &mut terms);
1271	    terms
1272	}
