1274	/// Lay out `tokens` after `prefix` with a fillSep (paragraph fill): place a
1275	/// token on the current line while `col + 1 + width <= width`, else break to a
1276	/// new line indented `indent`. Each token but the last carries a trailing
1277	/// comma. Matches the oracle's wrapping at column 69 (probes r3_wrap/r3_w2).
1278	fn fill_after_prefix(prefix: &str, tokens: &[String], indent: usize, width: usize) -> String {
1279	    let mut line = prefix.to_string();
1280	    let mut col = prefix.chars().count();
1281	    let pad = " ".repeat(indent);
1282	    let n = tokens.len();
1283	    for (i, tok) in tokens.iter().enumerate() {
1284	        let piece = if i + 1 < n {
1285	            format!("{},", tok)
1286	        } else {
1287	            tok.clone()
1288	        };
1289	        let w = piece.chars().count();
1290	        if col + 1 + w <= width {
1291	            line.push(' ');
1292	            line.push_str(&piece);
1293	            col += 1 + w;
1294	        } else {
1295	            line.push('\n');
1296	            line.push_str(&pad);
1297	            line.push_str(&piece);
1298	            col = indent + w;
1299	        }
1300	    }
1301	    line
1302	}
