1304	fn formula_terms_entry(entity: &str, name: &str, terms: &[String]) -> String {
1305	    let prefix = format!("  {} `{}' uses terms of the wrong form:", entity, name);
1306	    let tokens: Vec<String> = terms.iter().map(|t| format!("`{}'", t)).collect();
1307	    let head = fill_after_prefix(&prefix, &tokens, 4, FILL_WIDTH);
1308	    format!("{}\n  \n{}", head, FORMULA_TERMS_HELP)
1309	}
