1311	/// Standalone "Formula terms" check: reports ill-formed terms (free variables
1312	/// and applications of any symbol in `reducible`) in every lemma (source order)
1313	/// then every restriction (source order), merged into one topic block.
1314	pub fn formula_terms_reducible(
1315	    thy: &Theory,
1316	    reducible: &std::collections::BTreeSet<String>,
1317	) -> Vec<WfError> {
