1747	// 2. Fresh public constants
1748	// ---------------------------------------------------------------------------
1749	// A fresh-name literal (`~'foo'`) used directly in a rule is rejected; fresh
1750	// names must come from `Fr(~x)` premises. Constants are collected in the order
1751	// premises, conclusions, actions (observed via probe fpc_positions).
1752	pub fn fresh_public_constants(thy: &Theory) -> Vec<WfError> {
1753	    let mut entries: Vec<String> = Vec::new();
1754	    for r in protocol_rules(thy) {
1755	        let mut lits: Vec<String> = Vec::new();
1756	        for facts in [&r.premises, &r.conclusions, &r.actions] {
1757	            for f in facts {
1758	                for a in &f.args {
1759	                    collect_fresh_lits(a, &mut lits);
1760	                }
1761	            }
1762	        }
1763	        if lits.is_empty() {
1764	            continue;
1765	        }
1766	        // The constant list is a fillSep wrapped at column 69 with a 4-space
1767	        // continuation indent (probe r3_freshwrap).
1768	        let prefix = format!(
1769	            "  rule `{}': fresh public constants are not allowed:",
1770	            r.name
1771	        );
1772	        entries.push(fill_after_prefix(&prefix, &lits, 4, FILL_WIDTH));
1773	    }
1774	    if entries.is_empty() {
1775	        vec![]
1776	    } else {
1777	        vec![WfError::new(T_FRESH_PUB, entries.join("\n  \n"))]
1778	    }
1779	}
