1781	// ---------------------------------------------------------------------------
1782	// 5. Reserved prefixes (diff mode only)
1783	// ---------------------------------------------------------------------------
1784	// Fact names beginning with `DiffIntr`/`DiffProto` are reserved for the diff
1785	// translation. Only emitted for diff-mode theories (observed: silent otherwise).
1786	pub fn reserved_prefixes(thy: &Theory) -> Vec<WfError> {
1787	    if !thy.is_diff {
1788	        return vec![];
1789	    }
1790	    let mut entries: Vec<String> = Vec::new();
1791	    for r in protocol_rules(thy) {
1792	        // Order of collection: premises, actions, conclusions (probe rp_multi).
1793	        let mut hits: Vec<&Fact> = Vec::new();
1794	        for facts in [&r.premises, &r.actions, &r.conclusions] {
1795	            for f in facts {
1796	                if RESERVED_PREFIXES.iter().any(|p| f.name.starts_with(p)) {
1797	                    hits.push(f);
1798	                }
1799	            }
1800	        }
1801	        if hits.is_empty() {
1802	            continue;
1803	        }
1804	        let header = fill_words(&reserved_prefix_header_words(&r.name), 2, FILL_WIDTH);
1805	        let blocks: Vec<String> = hits
1806	            .iter()
1807	            .map(|f| {
1808	                let m = if f.persistent { "Persistent" } else { "Linear" };
1809	                format!(
1810	                    "    {}\n    (ProtoFact {} \"{}\" {},{},{})",
1811	                    pp_fact(f),
1812	                    m,
1813	                    f.name,
1814	                    f.args.len(),
1815	                    f.args.len(),
1816	                    m
1817	                )
1818	            })
1819	            .collect();
1820	        entries.push(format!("{}\n  \n{}", header, blocks.join("\n  \n")));
1821	    }
1822	    if entries.is_empty() {
1823	        vec![]
1824	    } else {
1825	        vec![WfError::new(T_RESERVED_PREFIX, entries.join("\n  \n"))]
1826	    }
1827	}
1828	
1829	fn reserved_prefix_header_words(rule: &str) -> Vec<String> {
1830	    [
1831	        "The",
1832	        "Rule",
1833	        &format!("`{}'", rule),
1834	        "contains",
1835	        "facts",
1836	        "with",
1837	        "reserved",
1838	        "prefixes",
1839	        "('DiffIntr',",
1840	        "'DiffProto')",
1841	        "inside",
1842	        "names:",
1843	    ]
1844	    .iter()
1845	    .map(|s| s.to_string())
1846	    .collect()
1847	}
