1942	// An `exists-trace` lemma marked `reuse` is rejected (observed trigger).
1943	pub fn lemma_annotations(thy: &Theory) -> Vec<WfError> {
1944	    let mut entries: Vec<String> = Vec::new();
1945	    for it in &thy.items {
1946	        if let TheoryItem::Lemma(l) = it {
1947	            let is_reuse = l.attributes.iter().any(|a| matches!(a, LemmaAttr::Reuse));
1948	            if is_reuse && l.trace_quantifier == TraceQuantifier::ExistsTrace {
1949	                entries.push(format!(
1950	                    "  Lemma `{}': cannot reuse 'exists-trace' lemmas",
1951	                    l.name
1952	                ));
1953	            }
1954	        }
1955	    }
1956	    if entries.is_empty() {
1957	        vec![]
1958	    } else {
1959	        vec![WfError::new(T_LEMMA_ANNOT, entries.join("\n  \n"))]
1960	    }
1961	}
