1963	// ---------------------------------------------------------------------------
1964	// 16. Multiplication restriction of rules
1965	// ---------------------------------------------------------------------------
1966	// A rule whose conclusions contain a multiplication (`*`) term is not
1967	// multiplication restricted. The "After replacing reducible function symbols"
1968	// rule renders identically to the original when the left-hand side has no
1969	// reducible symbols to replace (the general replacement is a documented gap).
1970	pub fn multiplication_restriction(thy: &Theory) -> Vec<WfError> {
1971	    let mut entries: Vec<String> = Vec::new();
1972	    for r in protocol_rules(thy) {
1973	        let mut mult_terms: Vec<String> = Vec::new();
1974	        for f in &r.conclusions {
1975	            for a in &f.args {
1976	                collect_mult_terms(a, &mut mult_terms);
1977	            }
1978	        }
1979	        if mult_terms.is_empty() {
1980	            continue;
1981	        }
1982	        let rule_pp = indent_block(&pp_rule(r), 4);
1983	        entries.push(format!(
1984	            "  The following rule is not multiplication restricted:\n{rule}\n  \n  After replacing reducible function symbols in lhs with variables:\n{rule}\n  \n    Terms with multiplication:  {terms}",
1985	            rule = rule_pp,
1986	            terms = mult_terms.join(", ")
1987	        ));
1988	    }
1989	    if entries.is_empty() {
1990	        vec![]
1991	    } else {
1992	        vec![WfError::new(T_MULRESTRICT, entries.join("\n  \n"))]
1993	    }
1994	}
