42	/// Render one topic block (header + underline + blank line + body) the way the
43	/// full report renders it, so a fixture can pin a single topic in isolation.
44	fn render_block(e: &report::WfError) -> String {
45	    format!("{}\n\n{}", underline_topic(&e.topic), e.message)
46	}
