114	fn lhs_not_rhs_no_dedup_source_order() {
115	    // A fact reused as an LHS-only premise across non-adjacent rules yields one
116	    // entry per rule, kept in source order (NOT grouped by fact name); a fact
117	    // repeated inside one rule's premises yields one entry per occurrence
118	    // (probes lhs1/lhs2).
119	    let thy = theory("T", vec![
120	        rule("A", vec![fact("AA", vec![mv("x")]), fact("BB", vec![mv("x")])], vec![], vec![]),
121	        rule("B", vec![fact("CC", vec![mv("x")])], vec![], vec![]),
122	        rule("C", vec![fact("AA", vec![mv("y")])], vec![], vec![]),
123	        rule("D", vec![fact("DD", vec![mv("x")]), fact("DD", vec![mv("x")])], vec![], vec![]),
124	    ]);
125	    let r = checks::fact_lhs_occur_no_rhs(&thy);
126	    assert_eq!(r.len(), 1);
127	    // Six numbered entries (single-digit index, two-space margin), separated by
128	    // a line of exactly two spaces; source order, no dedup.
129	    let want = [("A", "AA"), ("A", "BB"), ("B", "CC"), ("C", "AA"), ("D", "DD"), ("D", "DD")]
130	        .iter()
131	        .enumerate()
132	        .map(|(i, (rl, nm))| {
133	            format!(
134	                "  {}. in rule \"{}\":  factName `{}' arity: 1 multiplicity: Linear",
135	                i + 1,
136	                rl,
137	                nm
138	            )
139	        })
140	        .collect::<Vec<_>>()
