1	//! Round-5 corpus acceptance harness.
2	//!
3	//! `tests/corpus5/*.fml` holds every lemma and restriction formula printed by
4	//! the Haskell reference for the 71 round-5 gate-diff theories (captured from
5	//! oracle output; the reference reports NO formula-bundle topic for any of
6	//! them - their wf blocks contain no "Quantifier sorts", "Formula terms" or
7	//! " Formula guardedness" section). This test parses each printed formula
8	//! back into the wf-clean AST and asserts our formula bundle is silent too:
9	//! the guardedness DECISION (and the sort/term checks) must accept everything
10	//! the reference accepts.
11	
12	use wf_clean::*;
13	
14	// ---------------------------------------------------------------------------
15	// Parser for the oracle's pretty-printed (Unicode) formula syntax
16	// ---------------------------------------------------------------------------
17	
18	struct P {
19	    cs: Vec<char>,
20	    i: usize,
21	    /// Nullary function symbols of the source theory (from its printed
22	    /// `functions:` block); bare occurrences are constants, not variables.
23	    nullary: std::collections::BTreeSet<String>,
24	}
25	
26	#[derive(Debug)]
27	struct PErr(String);
28	
29	type PR<T> = Result<T, PErr>;
30	
31	impl P {
32	    fn new(s: &str, nullary: std::collections::BTreeSet<String>) -> Self {
33	        P {
34	            cs: s.chars().collect(),
35	            i: 0,
36	            nullary,
37	        }
38	    }
39	    fn ws(&mut self) {
40	        while self.i < self.cs.len() && self.cs[self.i].is_whitespace() {
41	            self.i += 1;
42	        }
43	    }
44	    fn peek(&mut self) -> Option<char> {
45	        self.ws();
46	        self.cs.get(self.i).copied()
47	    }
48	    fn eat(&mut self, c: char) -> PR<()> {
49	        if self.peek() == Some(c) {
50	            self.i += 1;
51	            Ok(())
52	        } else {
53	            Err(PErr(format!("expected {:?} at {}", c, self.i)))
54	        }
55	    }
56	    fn try_eat(&mut self, c: char) -> bool {
57	        if self.peek() == Some(c) {
58	            self.i += 1;
59	            true
60	        } else {
61	            false
62	        }
63	    }
64	    fn name(&mut self) -> PR<String> {
65	        self.ws();
66	        let start = self.i;
67	        while self.i < self.cs.len()
68	            && (self.cs[self.i].is_alphanumeric() || self.cs[self.i] == '_')
69	        {
70	            self.i += 1;
71	        }
72	        if self.i == start {
73	            return Err(PErr(format!("expected name at {}", self.i)));
74	        }
75	        Ok(self.cs[start..self.i].iter().collect())
76	    }
77	    /// `name` optionally followed by `.digits` (the printed variable index).
78	    fn name_idx(&mut self) -> PR<(String, u64)> {
79	        let n = self.name()?;
80	        let mut idx = 0u64;
81	        if self.cs.get(self.i) == Some(&'.')
82	            && self.cs.get(self.i + 1).map_or(false, |c| c.is_ascii_digit())
83	        {
84	            self.i += 1;
85	            let start = self.i;
86	            while self.i < self.cs.len() && self.cs[self.i].is_ascii_digit() {
87	                self.i += 1;
88	            }
89	            idx = self.cs[start..self.i]
90	                .iter()
91	                .collect::<String>()
92	                .parse()
93	                .unwrap();
94	        }
95	        Ok((n, idx))
96	    }
97	
98	    fn var(&mut self) -> PR<VarSpec> {
99	        let sort = match self.peek() {
100	            Some('#') => {
101	                self.i += 1;
102	                SortHint::Node
103	            }
104	            Some('~') => {
105	                self.i += 1;
106	                SortHint::Fresh
107	            }
108	            Some('$') => {
109	                self.i += 1;
110	                SortHint::Pub
111	            }
112	            Some('%') => {
113	                self.i += 1;
114	                SortHint::Nat
115	            }
116	            _ => SortHint::Untagged,
117	        };
118	        let (name, idx) = self.name_idx()?;
119	        Ok(VarSpec {
120	            name,
121	            idx,
122	            sort,
123	            typ: None,
124	        })
125	    }
126	
127	    fn term(&mut self) -> PR<Term> {
128	        match self.peek() {
129	            Some('\'') => {
130	                self.i += 1;
131	                let start = self.i;
132	                while self.i < self.cs.len() && self.cs[self.i] != '\'' {
133	                    self.i += 1;
134	                }
135	                let s: String = self.cs[start..self.i].iter().collect();
136	                self.eat('\'')?;
137	                Ok(Term::PubLit(s))
138	            }
139	            Some('<') => {
140	                self.i += 1;
141	                let mut items = vec![self.term()?];
142	                while self.try_eat(',') {
143	                    items.push(self.term()?);
144	                }
145	                self.eat('>')?;
146	                Ok(Term::Pair(items))
147	            }
148	            Some('(') => {
149	                // parenthesised term with infix AC operators, e.g. `(x++z)`
150	                self.i += 1;
151	                let mut t = self.term()?;
152	                loop {
153	                    self.ws();
154	                    if self.cs.get(self.i) == Some(&'+') && self.cs.get(self.i + 1) == Some(&'+') {
155	                        self.i += 2;
156	                        let r = self.term()?;
157	                        t = Term::BinOp(BinOp::Union, Box::new(t), Box::new(r));
158	                    } else if self.cs.get(self.i) == Some(&'⊕') {
159	                        self.i += 1;
160	                        let r = self.term()?;
161	                        t = Term::BinOp(BinOp::Xor, Box::new(t), Box::new(r));
162	                    } else {
163	                        break;
164	                    }
165	                }
166	                self.eat(')')?;
167	                Ok(t)
168	            }
169	            Some('~') if self.cs.get(self.i + 1) == Some(&'\'') => {
170	                self.i += 2;
171	                let start = self.i;
172	                while self.i < self.cs.len() && self.cs[self.i] != '\'' {
173	                    self.i += 1;
174	                }
175	                let s: String = self.cs[start..self.i].iter().collect();
176	                self.eat('\'')?;
177	                Ok(Term::FreshLit(s))
178	            }
179	            Some(c) if c == '#' || c == '~' || c == '$' || c == '%' => {
180	                Ok(Term::Var(self.var()?))
181	            }
182	            _ => {
183	                let (name, idx) = self.name_idx()?;
184	                if idx == 0 && self.cs.get(self.i) == Some(&'(') {
185	                    self.i += 1;
186	                    let mut args = Vec::new();
187	                    if self.peek() != Some(')') {
188	                        args.push(self.term()?);
189	                        while self.try_eat(',') {
190	                            args.push(self.term()?);
191	                        }
192	                    }
193	                    self.eat(')')?;
194	                    Ok(Term::App(name, args))
195	                } else if idx == 0 && name == "DH_neutral" {
196	                    Ok(Term::DhNeutral)
197	                } else if idx == 0 && self.nullary.contains(&name) {
198	                    Ok(Term::App(name, vec![]))
199	                } else {
200	                    Ok(Term::Var(VarSpec {
201	                        name,
202	                        idx,
203	                        sort: SortHint::Untagged,
204	                        typ: None,
205	                    }))
206	                }
207	            }
208	        }
209	    }
210	
211	    /// An atom starting at the current position: a fact/action, an equality,
212	    /// an ordering or a `last`. `persistent` facts carry a leading `!`.
213	    fn atom(&mut self) -> PR<Formula> {
214	        let persistent = self.try_eat('!');
215	        let t = self.term()?;
216	        match self.peek() {
217	            Some('@') => {
218	                self.i += 1;
219	                let tv = self.term()?;
220	                let fact = match t {
221	                    Term::App(name, args) => Fact {
222	                        persistent,
223	                        name,
224	                        args,
225	                        annotations: vec![],
226	                    },
227	                    Term::Var(v) => Fact {
228	                        persistent,
229	                        name: v.name,
230	                        args: vec![],
231	                        annotations: vec![],
232	                    },
233	                    other => return Err(PErr(format!("bad fact term {:?}", other))),
234	                };
235	                Ok(Formula::Atom(Atom::Action(fact, tv)))
236	            }
237	            Some('=') => {
238	                self.i += 1;
239	                let r = self.term()?;
240	                Ok(Formula::Atom(Atom::Eq(t, r)))
241	            }
242	            Some('<') => {
243	                self.i += 1;
244	                let r = self.term()?;
245	                Ok(Formula::Atom(Atom::Less(t, r)))
246	            }
247	            Some('⋖') => {
248	                self.i += 1;
249	                let r = self.term()?;
250	                Ok(Formula::Atom(Atom::LessMset(t, r)))
251	            }
252	            Some('⊏') => {
253	                self.i += 1;
254	                let r = self.term()?;
255	                Ok(Formula::Atom(Atom::Subterm(t, r)))
256	            }
257	            _ => match t {
258	                Term::App(name, args) if name == "last" && args.len() == 1 => {
259	                    Ok(Formula::Atom(Atom::Last(args.into_iter().next().unwrap())))
260	                }
261	                other => Err(PErr(format!("dangling term {:?}", other))),
262	            },
263	        }
264	    }
265	
266	    fn unary(&mut self) -> PR<Formula> {
267	        match self.peek() {
268	            Some('∀') | Some('∃') => {
269	                let forall = self.cs[self.i] == '∀';
270	                self.i += 1;
271	                let mut vars = Vec::new();
272	                loop {
273	                    self.ws();
274	                    if self.cs.get(self.i) == Some(&'.') {
275	                        self.i += 1;
276	                        break;
277	                    }
278	                    vars.push(self.var()?);
279	                }
280	                let body = self.formula()?;
281	                Ok(if forall {
282	                    Formula::Forall(vars, Box::new(body))
283	                } else {
284	                    Formula::Exists(vars, Box::new(body))
285	                })
286	            }
287	            Some('¬') => {
288	                self.i += 1;
289	                Ok(Formula::Not(Box::new(self.unary()?)))
290	            }
291	            Some('⊥') => {
292	                self.i += 1;
293	                Ok(Formula::False)
294	            }
295	            Some('⊤') => {
296	                self.i += 1;
297	                Ok(Formula::True)
298	            }
299	            Some('(') => {
300	                // Either `(formula)` or an atom whose left term is
301	                // parenthesised (`(x++z) = y`): try the atom first.
302	                let save = self.i;
303	                if let Ok(a) = self.atom() {
304	                    return Ok(a);
305	                }
306	                self.i = save;
307	                self.eat('(')?;
308	                let f = self.formula()?;
309	                self.eat(')')?;
310	                Ok(f)
311	            }
312	            _ => self.atom(),
313	        }
314	    }
315	
316	    fn formula(&mut self) -> PR<Formula> {
317	        let mut f = self.unary()?;
318	        loop {
319	            match self.peek() {
320	                Some('∧') => {
321	                    self.i += 1;
322	                    let r = self.unary()?;
323	                    f = Formula::And(Box::new(f), Box::new(r));
324	                }
325	                Some('∨') => {
326	                    self.i += 1;
327	                    let r = self.unary()?;
328	                    f = Formula::Or(Box::new(f), Box::new(r));
329	                }
330	                Some('⇒') => {
331	                    self.i += 1;
332	                    let r = self.formula()?;
333	                    f = Formula::Implies(Box::new(f), Box::new(r));
334	                }
335	                Some('⇔') => {
336	                    self.i += 1;
337	                    let r = self.formula()?;
338	                    f = Formula::Iff(Box::new(f), Box::new(r));
339	                }
340	                _ => break,
341	            }
342	        }
343	        Ok(f)
344	    }
345	}
346	
347	fn parse_formula(s: &str, nullary: std::collections::BTreeSet<String>) -> Result<Formula, String> {
348	    let mut p = P::new(s, nullary);
349	    let f = p.formula().map_err(|e| e.0)?;
350	    p.ws();
351	    if p.i != p.cs.len() {
352	        return Err(format!(
353	            "trailing input at {}: {:?}",
354	            p.i,
355	            p.cs[p.i..].iter().take(30).collect::<String>()
356	        ));
357	    }
358	    Ok(f)
359	}
360	
361	fn lemma_item(name: &str, f: Formula) -> TheoryItem {
362	    TheoryItem::Lemma(Lemma {
363	        name: name.to_string(),
364	        modulo: None,
365	        attributes: vec![],
366	        trace_quantifier: TraceQuantifier::AllTraces,
367	        formula: f,
368	        proof: None,
369	        plaintext: String::new(),
370	    })
371	}
372	
373	fn restriction_item(name: &str, f: Formula) -> TheoryItem {
374	    TheoryItem::Restriction(Restriction {
375	        name: name.to_string(),
376	        formula: f,
377	        attributes: vec![],
378	    })
379	}
