381	/// Every reference-accepted corpus formula must produce an empty formula
382	/// bundle (no Quantifier sorts, no Formula terms, no Formula guardedness).
383	#[test]
384	fn corpus5_reference_accepted_formulas_are_accepted() {
385	    let dir = concat!(env!("CARGO_MANIFEST_DIR"), "/tests/corpus5");
386	    let mut entries: Vec<_> = std::fs::read_dir(dir)
387	        .expect("tests/corpus5 missing")
388	        .map(|e| e.unwrap().path())
389	        .filter(|p| p.extension().map_or(false, |x| x == "fml"))
390	        .collect();
391	    entries.sort();
392	    assert!(
393	        entries.len() > 600,
394	        "expected the full corpus capture, found {}",
395	        entries.len()
396	    );
397	    let mut parse_failures = Vec::new();
398	    let mut report_failures = Vec::new();
399	    for path in &entries {
400	        let fname = path.file_name().unwrap().to_string_lossy().to_string();
401	        let text = std::fs::read_to_string(path).unwrap();
402	        let text = text.trim();
403	        let base = fname.split("__").next().unwrap().to_string();
404	        let fns_path = format!("{}/{}.fns", dir, base);
405	        let nullary: std::collections::BTreeSet<String> = std::fs::read_to_string(&fns_path)
406	            .map(|t| t.lines().map(|l| l.trim().to_string()).filter(|l| !l.is_empty()).collect())
407	            .unwrap_or_default();
408	        let f = match parse_formula(text, nullary) {
409	            Ok(f) => f,
410	            Err(e) => {
411	                parse_failures.push(format!("{}: {}", fname, e));
412	                continue;
413	            }
414	        };
415	        let is_lemma = fname.contains("__lemma__");
416	        let item = if is_lemma {
417	            lemma_item("L", f)
418	        } else {
419	            restriction_item("R", f)
420	        };
421	        let thy = Theory {
422	            is_diff: false,
423	            name: "corpus".into(),
424	            configuration: None,
425	            items: vec![item],
426	        };
427	        let r = wf_clean::checks::formula_reports(&thy, &std::collections::BTreeSet::new());
428	        if !r.is_empty() {
429	            report_failures.push(format!(
430	                "{}: [{}] {}",
431	                fname,
432	                r[0].topic,
433	                r[0].message.lines().take(3).collect::<Vec<_>>().join(" | ")
434	            ));
435	        }
436	    }
437	    assert!(
438	        parse_failures.is_empty(),
439	        "{} formulas failed to parse:\n{}",
440	        parse_failures.len(),
441	        parse_failures.join("\n")
442	    );
443	    assert!(
444	        report_failures.is_empty(),
445	        "{} reference-accepted formulas were reported:\n{}",
446	        report_failures.len(),
447	        report_failures.join("\n")
448	    );
449	}
